import os
import logging

# Set up logging
logging.basicConfig(level=logging.INFO)

class RedisClient:
    def __init__(self):
        self.redis_nodes = [
            {'host': 'redis-node-1', 'port': 6379},
            {'host': 'redis-node-2', 'port': 6380},
            # Add more nodes as needed
        ]
        self.ttl_values: Dict[str, int] = {
            'session_tokens': 3600,  # 1 hour
            'api_keys': 86400  # 24 hours
        }

    def connect(self):
        try:
            self.redis_clients = []
            for node in self.redis_nodes:
                client = redis.Redis(host=node['host'], port=node['port'])
                self.redis_clients.append(client)
            logging.info('Connected to Redis cluster')
        except Exception as e:
            logging.error(f'Failed to connect to Redis: {e}')

    def store_data(self, key: str, value: str):
        if key in self.ttl_values:
            ttl = self.ttl_values[key]
            for client in self.redis_clients:
                try:
                    client.set(key, value)
                    client.expire(key, ttl)
                    logging.info(f'Stored {key} with TTL {ttl}')
                except Exception as e:
                    logging.error(f'Failed to store {key}: {e}')

    def get_data(self, key: str):
        for client in self.redis_clients:
            try:
                value = client.get(key)
                if value is not None:
                    return value.decode('utf-8')
                else:
                    logging.info(f'{key} not found in Redis')
            except Exception as e:
                logging.error(f'Failed to retrieve {key}: {e}')

    def close(self):
        for client in self.redis_clients:
            try:
                client.close()
            except Exception as e:
                logging.error(f'Failed to close Redis connection: {e}')

